#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(char*)a - *(char*)b);
}

int main() {
    int n;
    scanf("%d", &n);
    char l[2*n + 1];
    scanf("%s", l);
    char a[n + 1];
    char b[n + 1];
    strncpy(a, l, n);
    a[n] = '\0';
    strncpy(b, l + n, n);
    b[n] = '\0';
    qsort(a, n, sizeof(char), compare);
    qsort(b, n, sizeof(char), compare);
    int count1 = 1, count2 = 1, flag = 0;
    for (int i = 0; i < n; i++) {
        if (a[i] > b[i]) {
            count1 = 0;
        } else {
            count2 = 0;
        }
        if ((!count1 && !count2) || (a[i] == b[i])) {
            printf("NO\n");
            flag = 1;
            break;
        }
    }
    if (flag == 0) {
        printf("YES\n");
    }
    return 0;
}
